import jsonimport deeplimport reimport osimport shutildef translate_json():    target_text = input("Enter the target text: ").lower()    folder = input("Enter the folder path: ")    api_key = input("Enter the api key: ")    backup_folder = folder + "_backup"    translate_sections = ["gameTitle", "armorTypes", "weaponTypes", "equipTypes", "skillTypes", "elements", "terms"]    def walk(node,filename,in_system=False):        if isinstance(node,list):            for i in range(len(node)):                if in_system and isinstance(node[i],str):                   node[i] = translate(node[i])                else:                   walk(node[i],filename,in_system)        elif isinstance(node,dict):            if node.get("code") in [401,405]:                speech = node["parameters"][0]                if isinstance(speech,str):                    node["parameters"][0] = translate(speech)            elif node.get("code") == 102:                choices = node["parameters"][0]                for i in range (len(choices)):                   if isinstance(choices[i],str):                       choices[i]= translate(choices[i])            else:                for key,value in node.items():                   if in_system and isinstance(value,str):                       node[key] = translate(value)                   elif key in ["description","nickname","profile","message1","message2"] and isinstance(value,str):                       node[key] = translate(value)                   elif filename in ["Actors.json", "Items.json", "Skills.json", "Weapons.json", "Armors.json","Classes.json", "Enemies.json", "States.json"] and key == "name":                       node["name"] = translate(value)                   else:                        walk(value,filename,in_system)    def translate(text):        if not text.strip():            return text        codes = []        def hide(match):            codes.append(match.group(0))            return "ZZ%dZZ"  % (len(codes) - 1)        masked = re.sub(r"\\[A-Za-z]\[\d+\]|%\d+|\\[.|!><^{}]",hide,text)        try:           translator = deepl.Translator(api_key)           result = translator.translate_text(masked, target_lang=target_text.upper()).text        except Exception as e:           print(e)           return text        for i in range(len(codes)):            result = result.replace("ZZ%dZZ" % i,codes[i])        return result    if not os.path.exists(backup_folder):        shutil.copytree(folder,backup_folder)        print("copied folder")    try:            for name in os.listdir(folder):             if not name.endswith(".json"):                continue             path = os.path.join(folder,name)             print("Translate:", name)             try:               with open(path, encoding="utf-8") as f:                 data = json.load(f)             except json.JSONDecodeError as e:               print(f"File {name} could not be read: {e}")               continue             if name == "System.json":                 for section in translate_sections:                     if section in data:                         walk(data[section],name,True)             else:                 walk(data,name)             try:                json_str = json.dumps(data,ensure_ascii=False,indent=2)                with open(path,"w",encoding="utf-8") as f:                  f.write(json_str)             except Exception as e:                print(f"Error in file{name}: ",e)    except FileNotFoundError:        print("Folder not found")    print("ready")